function SeriesEvergreenView({ series, category }: { series: any, category: string }) {
  const now = new Date();
  
  // Split events into Upcoming and Past
  const upcoming = series.events.filter((e: any) => e.dueAt && new Date(e.dueAt) >= now);
  
  // Past events sorted newest-first
  const past = series.events.filter((e: any) => e.dueAt && new Date(e.dueAt) < now).sort((a: any, b: any) => new Date(b.dueAt).getTime() - new Date(a.dueAt).getTime());

  return (
    <main className="min-h-screen bg-black text-white font-sans selection:bg-emerald-500/30 pt-12 pb-20">
      <div className="max-w-4xl mx-auto px-5">
        
        {/* Breadcrumbs */}
        <div className="flex items-center gap-2 text-xs font-bold uppercase tracking-widest text-zinc-500 mb-8">
          <Link href="/" className="hover:text-white transition">Home</Link>
          <span>/</span>
          <span className="text-emerald-400">{series.category}</span>
          <span>/</span>
          <span className="text-zinc-300">Series</span>
        </div>

        {/* Header */}
        <header className="mb-14 border-b border-zinc-800 pb-10">
          <p className="mb-3 text-xs font-bold uppercase tracking-widest text-emerald-400 flex items-center gap-2">
            <CalendarDays className="w-4 h-4" /> Official Schedule
          </p>
          <h1 className="text-4xl md:text-5xl font-black tracking-tight mb-4">
            {series.title}
          </h1>
          <p className="text-lg text-zinc-400 leading-relaxed max-w-2xl">
            Track the full, mathematically verified schedule for {series.title}. Below you will find exact countdowns for upcoming dates, plus a complete historical archive of past occurrences.
          </p>
        </header>

        {/* UPCOMING SECTION */}
        <section className="mb-16">
          <h2 className="text-2xl font-bold tracking-tight mb-2 flex items-center gap-3">
            <div className="w-2.5 h-2.5 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_10px_rgba(16,185,129,0.8)]" />
            Upcoming Dates
          </h2>
          <p className="text-sm text-zinc-500 mb-6 font-medium">Click any date for the exact real-time countdown and official source verification.</p>
          
          {upcoming.length === 0 ? (
            <div className="p-8 border border-dashed border-zinc-800 rounded-2xl text-center text-zinc-500 text-sm">
              No upcoming dates are currently scheduled.
            </div>
          ) : (
            <div className="space-y-4">
              {upcoming.map((evt: any) => (
                <Link key={evt.id} href={`/${category.toLowerCase()}/${evt.slug}`} className="group block">
                  <div className="flex flex-col sm:flex-row sm:items-center justify-between bg-zinc-900/40 border border-zinc-800 hover:border-emerald-500/50 hover:bg-zinc-900 rounded-2xl p-6 transition-all duration-200">
                    <div>
                      <h3 className="text-lg font-bold text-white group-hover:text-emerald-300 transition-colors mb-1">{evt.title}</h3>
                      <p className="text-sm text-emerald-400 font-mono">
                        {new Intl.DateTimeFormat('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric', timeZone: 'UTC' }).format(evt.dueAt)}
                      </p>
                    </div>
                    <div className="mt-4 sm:mt-0 flex items-center text-sm font-bold text-zinc-400 group-hover:text-emerald-400 transition-colors">
                      View Countdown <ExternalLink className="w-4 h-4 ml-2" />
                    </div>
                  </div>
                </Link>
              ))}
            </div>
          )}
        </section>

        {/* PAST HISTORY SECTION */}
        <section>
          <h2 className="text-2xl font-bold tracking-tight mb-2 flex items-center gap-3">
            <History className="w-6 h-6 text-zinc-500" />
            Past History
          </h2>
          <p className="text-sm text-zinc-500 mb-6 font-medium">Archived dates for historical reference and pattern analysis.</p>

          {past.length === 0 ? (
            <div className="p-8 border border-dashed border-zinc-800 rounded-2xl text-center text-zinc-500 text-sm">
              No past history available yet.
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {past.map((evt: any) => (
                <Link key={evt.id} href={`/${category.toLowerCase()}/${evt.slug}`} className="group block">
                  <div className="bg-black border border-zinc-800 hover:border-zinc-600 rounded-2xl p-5 transition-all duration-200">
                    <h3 className="text-base font-bold text-zinc-300 group-hover:text-white transition-colors mb-1">{evt.title}</h3>
                    <p className="text-sm text-zinc-500">
                      Occurred on {new Intl.DateTimeFormat('en-US', { month: 'short', day: 'numeric', year: 'numeric', timeZone: 'UTC' }).format(evt.dueAt)}
                    </p>
                  </div>
                </Link>
              ))}
            </div>
          )}
        </section>

      </div>
    </main>
  );
}


// ============================================================================
// VIEW 2: THE GOD-TIER TERMINAL (SINGLE EVENT)
// ============================================================================
async function SingleEventView({ dbEvent, category, slug }: { dbEvent: any, category: string, slug: string }) {
  const evt = mapDbToRecord(dbEvent);
  const dbAllEvents = await prisma.event.findMany();
  const allEvents = dbAllEvents.map(mapDbToRecord);

  const historicalData = evt.seriesKey ? aggregateSeries(allEvents, evt.seriesKey) : null;
  const cci = historicalData?.cci;
  
  let activeProgram: "SNAP" | "SSA" | "VA" | null = null;
  const lowerTitle = (evt.title || "").toLowerCase();
  
  if (lowerTitle.includes("snap") || lowerTitle.includes("calfresh")) { activeProgram = "SNAP"; } 
  else if (lowerTitle.includes("ssa") || lowerTitle.includes("ssi") || lowerTitle.includes("social security")) { activeProgram = "SSA"; } 
  else if (lowerTitle.includes("va-") || lowerTitle.includes("va disability")) { activeProgram = "VA"; }

  const catalogData = await loadAnomalyCatalog(activeProgram);

  const diffMins = Math.floor((Date.now() - dbEvent.updatedAt.getTime()) / 60000);
  const updatedString = diffMins < 60 ? `${diffMins}m ago` : `${Math.floor(diffMins / 60)}h ago`;

  return (
    <main className="min-h-screen bg-black text-white font-sans selection:bg-emerald-500/30 pt-12 pb-20">
      <CountdownJsonLd event={{
        title: dbEvent.title,
        description: dbEvent.seoDescription || `Countdown to ${dbEvent.title}`,
        dueAt: dbEvent.dueAt,
        category: dbEvent.category,
        url: `https://whenisdue.com/${dbEvent.category.toLowerCase()}/${slug}`
      }} />

      <div className="max-w-4xl mx-auto px-5">
        <div className="flex items-center gap-2 text-xs font-bold uppercase tracking-widest text-zinc-500 mb-6">
          <Link href="/" className="hover:text-white transition">Home</Link>
          <span>/</span>
          <span className="text-emerald-400">{dbEvent.category}</span>
          {dbEvent.seriesId && (
            <>
              <span>/</span>
              <Link href={`/${category}/${dbEvent.seriesId}`} className="hover:text-white transition">Series</Link>
            </>
          )}
        </div>

        <div className="rounded-3xl border border-zinc-800 bg-zinc-950 p-6 md:p-10 shadow-2xl relative overflow-hidden mb-12">
          <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[150%] h-32 bg-emerald-500/10 blur-[100px] pointer-events-none" />

          <div className="flex flex-wrap items-center gap-4 mb-8 border-b border-zinc-800/50 pb-4 relative z-10">
            <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase tracking-widest text-emerald-400 bg-emerald-400/10 px-2.5 py-1 rounded-md border border-emerald-400/20">
              <div className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" />
              Live Sync
            </div>
            <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase tracking-widest text-zinc-400">
              <Clock className="w-3 h-3" />
              Updated {updatedString}
            </div>
            <div className="flex items-center gap-1.5 text-[10px] font-bold uppercase tracking-widest text-zinc-400">
              <ShieldCheck className="w-3 h-3" />
              Verified Sourced
            </div>
          </div>

          <h1 className="text-3xl md:text-5xl font-black tracking-tight mb-4 relative z-10">
            {dbEvent.title}
          </h1>

          <p className="text-base md:text-lg text-zinc-400 max-w-2xl mb-10 leading-relaxed relative z-10">
            {dbEvent.seoDescription || `Track the exact timing, official schedule, and real-time countdown for ${dbEvent.title}.`}
          </p>

          {dbEvent.dateStatus === 'EXACT' && dbEvent.dueAt ? (
            <div className="space-y-6 relative z-10">
              <div className="bg-black/50 border border-zinc-800/80 p-6 rounded-2xl">
                <Countdown targetIso={dbEvent.dueAt.toISOString()} />
              </div>
              <EventTimeDisplay dueAt={dbEvent.dueAt} officialZone={dbEvent.timeZone || 'UTC'} />
              
              <div className="flex flex-wrap gap-3 pt-2">
                <button className="flex items-center gap-2 bg-white text-black font-bold px-5 py-3 rounded-xl text-sm hover:scale-[1.02] transition-transform">
                  <CalendarPlus className="w-4 h-4" />
                  Add to Calendar
                </button>
                {dbEvent.sourceUrl && (
                  <a href={dbEvent.sourceUrl} target="_blank" rel="noopener noreferrer" className="flex items-center gap-2 border border-zinc-700 bg-zinc-900 px-5 py-3 rounded-xl text-sm font-bold text-zinc-300 hover:text-white hover:bg-zinc-800 transition-colors">
                    Official Source <ExternalLink className="w-4 h-4" />
                  </a>
                )}
              </div>
            </div>
          ) : (
            <div className="p-8 rounded-2xl bg-amber-500/10 border border-amber-500/20 text-center relative z-10">
              <p className="text-amber-400 font-bold tracking-widest uppercase mb-2 text-sm">{dbEvent.dateStatus.replace('_', ' ')}</p>
              <p className="text-3xl font-black text-white mb-2">{dbEvent.dateLabel || 'Official Date Pending'}</p>
              <p className="text-zinc-400 text-sm">We are actively monitoring official sources for the exact timestamp.</p>
              {dbEvent.sourceUrl && (
                <a href={dbEvent.sourceUrl} target="_blank" rel="noopener noreferrer" className="inline-flex items-center gap-2 mt-6 border border-zinc-700 bg-zinc-900 px-5 py-3 rounded-xl text-sm font-bold text-zinc-300 hover:text-white transition-colors">
                  Check Official Source <ExternalLink className="w-4 h-4" />
                </a>
              )}
            </div>
          )}
        </div>

        <Suspense fallback={<div className="p-8 border border-white/10 rounded-xl text-center text-sm opacity-50 animate-pulse">Loading verified schedule data...</div>}>
          <VerificationBlock statusLabel={evt.statusLabel} sourceUrl={evt.sourceUrl} />
          {evt.officialDates && evt.officialDates.length > 0 && <FederalSnapshot event={evt} cci={cci} />}        
          {evt.eventType === "SCHEDULE" && evt.officialDates && evt.officialDates.length > 0 ? (
            <ScheduleTable dates={evt.officialDates} />
          ) : (
            <div className="mt-8 p-8 border border-white/5 bg-zinc-900/30 rounded-2xl text-center">
              <p className="text-zinc-500 text-sm font-medium tracking-tight">Full historical schedule data is being synced.</p>
            </div>
          )}
        </Suspense>
      </div>
    </main>
  );
}